import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
vi.mock("node:child_process", async (importOriginal) => {
    const actual = await importOriginal();
    return { ...actual, execFileSync: vi.fn() };
});
vi.mock("node:os", async (importOriginal) => {
    const actual = await importOriginal();
    return {
        ...actual,
        default: { ...actual, platform: vi.fn(() => "darwin") },
    };
});
import { execFileSync } from "node:child_process";
import os from "node:os";
import { buildCloseStudioWindowsAppleScript, closeStudioWindowsBySession, computeWindowArgs, matchChromiumBrowser, shouldDisableChromelessWindows, } from "./browser.js";
const BROWSERS = [
    {
        name: "Google Chrome",
        defaultIds: ["com.google.chrome", "google-chrome.desktop", "chromehtml"],
        binaryPaths: [],
    },
    {
        name: "Brave",
        defaultIds: ["com.brave.browser", "brave-browser.desktop", "bravehtml"],
        binaryPaths: [],
    },
    {
        name: "Microsoft Edge",
        defaultIds: [
            "com.microsoft.edgemac",
            "microsoft-edge.desktop",
            "msedgehtm",
        ],
        binaryPaths: [],
    },
];
describe("matchChromiumBrowser", () => {
    it("returns null when default id is null", () => {
        expect(matchChromiumBrowser(null, BROWSERS)).toBeNull();
    });
    it("matches macOS bundle id exactly", () => {
        expect(matchChromiumBrowser("com.google.chrome", BROWSERS)?.name).toBe("Google Chrome");
    });
    it("matches Linux .desktop filename", () => {
        expect(matchChromiumBrowser("brave-browser.desktop", BROWSERS)?.name).toBe("Brave");
    });
    it("matches Windows ProgId including trailing hash", () => {
        expect(matchChromiumBrowser("msedgehtm.d7e6b94c12345678", BROWSERS)?.name).toBe("Microsoft Edge");
    });
    it("returns null for non-chromium defaults", () => {
        expect(matchChromiumBrowser("org.mozilla.firefox", BROWSERS)).toBeNull();
        expect(matchChromiumBrowser("com.apple.safari", BROWSERS)).toBeNull();
        expect(matchChromiumBrowser("firefoxurl-12345", BROWSERS)).toBeNull();
    });
});
describe("shouldDisableChromelessWindows", () => {
    const ENV_VARS = [
        "CODEX_SANDBOX",
        "CODEX_CI",
        "CODEX_THREAD_ID",
        "BITFAB_DISABLE_CHROME_APP_WINDOWS",
        "BITFAB_ENABLE_CHROME_APP_WINDOWS",
    ];
    const saved = {};
    const originalPlatform = process.platform;
    beforeEach(() => {
        for (const key of ENV_VARS) {
            saved[key] = process.env[key];
            delete process.env[key];
        }
        Object.defineProperty(process, "platform", { value: "darwin" });
    });
    afterEach(() => {
        for (const key of ENV_VARS) {
            if (saved[key] === undefined) {
                delete process.env[key];
            }
            else {
                process.env[key] = saved[key];
            }
        }
        Object.defineProperty(process, "platform", { value: originalPlatform });
    });
    it("disables chromeless windows by default", () => {
        expect(shouldDisableChromelessWindows()).toBe(true);
    });
    it("ignores Codex environment signals", () => {
        process.env.CODEX_SANDBOX = "seatbelt";
        process.env.CODEX_CI = "1";
        process.env.CODEX_THREAD_ID = "tid_abc123";
        expect(shouldDisableChromelessWindows()).toBe(true);
    });
    it("allows chromeless windows through the temporary opt-in", () => {
        process.env.BITFAB_ENABLE_CHROME_APP_WINDOWS = "1";
        expect(shouldDisableChromelessWindows()).toBe(false);
    });
    it("keeps the legacy disable override authoritative", () => {
        process.env.BITFAB_ENABLE_CHROME_APP_WINDOWS = "1";
        process.env.BITFAB_DISABLE_CHROME_APP_WINDOWS = "1";
        expect(shouldDisableChromelessWindows()).toBe(true);
    });
});
describe("computeWindowArgs", () => {
    it("returns no args when work area is null", () => {
        expect(computeWindowArgs(null)).toEqual([]);
    });
    it("centers a sized window inside a work area at origin 0,0", () => {
        // 2056×1290 work area → 95% = 1953×1225, centered at (51, 32)
        expect(computeWindowArgs({ x: 0, y: 0, width: 2056, height: 1290 })).toEqual(["--window-size=1953,1225", "--window-position=51,32"]);
    });
    it("offsets position by the work area origin (menubar/dock)", () => {
        // Work area starts at y=39 below a macOS menubar; position must be
        // relative to the full screen, so y = 39 + (1290-1225)/2 = 71
        expect(computeWindowArgs({ x: 0, y: 39, width: 2056, height: 1290 })).toEqual(["--window-size=1953,1225", "--window-position=51,71"]);
    });
});
describe("buildCloseStudioWindowsAppleScript", () => {
    const SID = "11111111-1111-4111-8111-111111111111";
    it("matches tabs by session id and closes only the tab", () => {
        const script = buildCloseStudioWindowsAppleScript("Google Chrome", SID);
        expect(script).toContain(`(URL of t) contains "${SID}"`);
        expect(script).toContain("close t");
        expect(script).not.toContain("close w");
    });
    it("guards with `is running` so it never launches the app", () => {
        const script = buildCloseStudioWindowsAppleScript("Brave Browser", SID);
        expect(script).toContain(`if application "Brave Browser" is running then`);
        expect(script.trim().endsWith("end if")).toBe(true);
    });
});
describe("closeStudioWindowsBySession", () => {
    const SID = "22222222-2222-4222-8222-222222222222";
    beforeEach(() => {
        vi.mocked(execFileSync).mockClear();
        vi.mocked(os.platform).mockReturnValue("darwin");
    });
    it("runs osascript for each Chromium app on macOS", () => {
        closeStudioWindowsBySession(SID);
        expect(execFileSync).toHaveBeenCalled();
        for (const call of vi.mocked(execFileSync).mock.calls) {
            expect(call[0]).toBe("osascript");
            const args = call[1];
            expect(args[0]).toBe("-e");
            expect(args[1]).toContain(SID);
        }
    });
    it("covers every browser the launcher can open a window in (not just Chrome)", () => {
        // Other users' default browsers: the close must target Brave/Edge/Chromium
        // too, with the real macOS .app names AppleScript expects.
        closeStudioWindowsBySession(SID);
        const targeted = vi
            .mocked(execFileSync)
            .mock.calls.map((c) => {
            const script = c[1][1];
            return script.match(/application "([^"]+)" is running/)?.[1];
        })
            .filter(Boolean);
        expect(targeted).toEqual(expect.arrayContaining([
            "Google Chrome",
            "Chromium",
            "Brave Browser",
            "Microsoft Edge",
        ]));
    });
    it("is a no-op off macOS", () => {
        vi.mocked(os.platform).mockReturnValue("linux");
        closeStudioWindowsBySession(SID);
        expect(execFileSync).not.toHaveBeenCalled();
    });
    it("refuses an id with shell/script metacharacters", () => {
        closeStudioWindowsBySession('evil" tell application "Finder');
        expect(execFileSync).not.toHaveBeenCalled();
    });
    it("does nothing for an empty session id", () => {
        closeStudioWindowsBySession("");
        expect(execFileSync).not.toHaveBeenCalled();
    });
});
